        """Attempt horizontal move; revert if invalid."""
        old_x = self.x
        self.x += dx
        if not is_valid_position(self, grid):
            self.x = old_x

    def soft_drop(self, grid):
        """Move down one; return False if it would collide."""
        old_y = self.y
        self.y += 1
        if not is_valid_position(self, grid):
            self.y = old_y
            return False
        return True

    def hard_drop(self, grid):
        """Drop until collision; lock in place at the end."""
        while self.soft_drop(grid):
            pass
        return False  # indicates it landed

