    screen.blit(text, (GRID_WIDTH * CELL_SIZE + 10, 10))

    # Offset to position the preview nicely
    offset_x = GRID_WIDTH * CELL_SIZE + 10
    offset_y = 40

    for row in range(len(piece.shape)):
        for col in range(len(piece.shape[row])):
            if piece.shape[row][col]:
                x = col
                y = row
                pygame.draw.rect(screen, piece.color,
                                 (offset_x + x * CELL_SIZE, offset_y + y * CELL_SIZE, CELL_SIZE, CELL_SIZE))

def draw_score(screen, score):
    """Draw the current score."""
    font = pygame.font.Font(None, 36)
    text = font.render(f"Score: {score}", True, WHITE)
    screen.blit(text, (GRID_WIDTH * CELL_SIZE + 10, SCREEN_HEIGHT - 50))

def main():
    pygame.init()
    screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
    pygame.display.set_caption("Tetris Bejeweled")

    game_state = GameState()
    clock = pygame.time.Clock()
    fall_speed = 1  # Cells per second
    last_fall_time = pygame.time.get_ticks()

    running = True
    while running:
        screen.fill(BLACK)
        current_time = pygame.time.get_ticks()

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    game_state.move_left()
                if event.key == pygame.K_RIGHT:
                    game_state.move_right()
                if event.key == pygame.K_UP:
                    game_state.rotate()
                if event.key == pygame.K_DOWN:
                    game_state.update()

        if current_time - last_fall_time > 1000 / fall_speed:
            game_state.update()
            last_fall_time = current_time

        draw_grid(screen, game_state.grid)
        draw_piece(screen, game_state.current_piece)
        draw_next_piece(screen, game_state.next_piece)
        draw_score(screen, game_state.score)

        pygame.display.flip()
        clock.tick(60)

    pygame.quit()

if __name__ == "__main__":
    main()
